1	export type Coordinate = [number, number];
2	
3	const parseCoordinate = (cellString: string): Coordinate => {
4	  const [x, y] = cellString.split(",").map(Number);
5	  return [x, y];
6	};
7	
8	const NEIGHBOR_OFFSETS: Coordinate[] = [
9	  [-1, -1], [-1, 0], [-1, 1],
10	  [0, -1],           [0, 1],
11	  [1, -1],  [1, 0],  [1, 1]
12	];
13	
14	const formatCoordinate = (x: number, y: number): string => {
15	  return `${x},${y}`;
16	};
17	
18	const countLiveNeighbors = (cell: string, livingCells: Set<string>): number => {
19	  const [x, y] = parseCoordinate(cell);
20	  let count = 0;
21	  for (const [dx, dy] of NEIGHBOR_OFFSETS) {
22	    if (livingCells.has(formatCoordinate(x + dx, y + dy))) {
23	      count++;
24	    }
25	  }
26	  return count;
27	};
28	
29	const shouldCellSurviveOrBeBorn = (isAlive: boolean, liveNeighborCount: number): boolean => {
30	  if (isAlive && (liveNeighborCount === 2 || liveNeighborCount === 3)) {
31	    return true; // Cell survives with 2 or 3 neighbors
32	  }
33	  if (!isAlive && liveNeighborCount === 3) {
34	    return true; // Dead cell becomes alive with exactly 3 neighbors
35	  }
36	  return false;
37	};
38	
39	/**
40	 * Computes the next generation of cells in Conway's Game of Life.
41	 *
42	 * Cells are represented as strings in the format "x,y" where x and y are integers.
43	 *
44	 * Rules applied:
45	 * - Cell with < 2 neighbors dies (underpopulation)
46	 * - Cell with 2-3 neighbors survives
47	 * - Cell with > 3 neighbors dies (overpopulation)
48	 * - Dead cell with exactly 3 neighbors becomes alive (reproduction)
49	 *
50	 * @param cells Set of living cells as coordinate strings "x,y"
51	 * @returns Set of living cells in the next generation
52	 */
53	export function nextGeneration(cells: Set<string>): Set<string> {
54	  if (cells.size === 0) {
55	    return new Set();
56	  }
57	
58	  const cellsToCheck = new Set<string>();
59	
60	  // Add all living cells and their neighbors to check
61	  for (const cell of cells) {
62	    const [x, y] = parseCoordinate(cell);
63	    cellsToCheck.add(cell);
64	    for (const [dx, dy] of NEIGHBOR_OFFSETS) {
65	      cellsToCheck.add(formatCoordinate(x + dx, y + dy));
66	    }
67	  }
68	
69	  const nextGen = new Set<string>();
70	
71	  // Check each cell and determine if it survives or is born
72	  for (const cell of cellsToCheck) {
73	    const liveNeighborCount = countLiveNeighbors(cell, cells);
74	    const isAlive = cells.has(cell);
75	
76	    if (shouldCellSurviveOrBeBorn(isAlive, liveNeighborCount)) {
77	      nextGen.add(cell);
78	    }
79	  }
80	
81	  return nextGen;
82	}
